import {
  Combobox as ComboboxPrimitive,
  type CollectionItem,
  type ComboboxRootComponent as ArkComboboxRootComponent,
  type ComboboxRootProps as ArkComboboxRootProps,
  type ComboboxRootProviderComponent as ArkComboboxRootProviderComponent,
  type ComboboxRootProviderProps as ArkComboboxRootProviderProps,
  useCombobox,
  useComboboxContext,
} from '@ark-ui/react/combobox';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef, ForwardedRef, ReactNode } from 'react';
import { forwardRef } from 'react';
import { CheckIcon, ChevronUpDownIcon, CloseIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import {
  OverlayPortal,
  OverlayPortalProvider,
  type OverlayPortalProps,
} from '@/lib/moduix/overlayPortal';
import styles from './Combobox.module.css';

type ComboboxRootProps<T extends CollectionItem> = ArkComboboxRootProps<T> & OverlayPortalProps;
type ComboboxRootProviderProps<T extends CollectionItem> = ArkComboboxRootProviderProps<T> &
  OverlayPortalProps;

const ComboboxRoot = forwardRef(function ComboboxRoot<T extends CollectionItem>(
  { className, portalled, portalRef, ...props }: ComboboxRootProps<T>,
  ref: ForwardedRef<HTMLDivElement>,
) {
  return (
    <OverlayPortalProvider portalled={portalled} portalRef={portalRef}>
      <ComboboxPrimitive.Root
        ref={ref}
        data-slot="combobox-root"
        className={clsx(styles.root, normalizeClassName(className))}
        {...props}
      />
    </OverlayPortalProvider>
  );
}) as ArkComboboxRootComponent<OverlayPortalProps>;

const ComboboxRootProvider = forwardRef(function ComboboxRootProvider<T extends CollectionItem>(
  { className, portalled, portalRef, ...props }: ComboboxRootProviderProps<T>,
  ref: ForwardedRef<HTMLDivElement>,
) {
  return (
    <OverlayPortalProvider portalled={portalled} portalRef={portalRef}>
      <ComboboxPrimitive.RootProvider
        ref={ref}
        data-slot="combobox-root-provider"
        className={clsx(styles.root, normalizeClassName(className))}
        {...props}
      />
    </OverlayPortalProvider>
  );
}) as ArkComboboxRootProviderComponent<OverlayPortalProps>;

const ComboboxLabel = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Label>,
  ComponentProps<typeof ComboboxPrimitive.Label>
>(function ComboboxLabel({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Label
      ref={ref}
      data-slot="combobox-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxControl = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Control>,
  ComponentProps<typeof ComboboxPrimitive.Control>
>(function ComboboxControl({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Control
      ref={ref}
      data-slot="combobox-control"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxInput = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Input>,
  ComponentProps<typeof ComboboxPrimitive.Input>
>(function ComboboxInput({ asChild, className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Input
      ref={ref}
      data-slot="combobox-input"
      asChild={asChild}
      className={clsx(!asChild && styles.input, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxClearTrigger = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.ClearTrigger>,
  ComponentProps<typeof ComboboxPrimitive.ClearTrigger>
>(function ComboboxClearTrigger({ className, children, ...props }, ref) {
  return (
    <ComboboxPrimitive.ClearTrigger
      ref={ref}
      data-slot="combobox-clear-trigger"
      className={clsx(styles.clearTrigger, normalizeClassName(className))}
      {...props}
    >
      {children ?? <CloseIcon />}
    </ComboboxPrimitive.ClearTrigger>
  );
});

const ComboboxTrigger = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Trigger>,
  ComponentProps<typeof ComboboxPrimitive.Trigger>
>(function ComboboxTrigger({ className, children, ...props }, ref) {
  return (
    <ComboboxPrimitive.Trigger
      ref={ref}
      data-slot="combobox-trigger"
      className={clsx(styles.trigger, normalizeClassName(className))}
      {...props}
    >
      {children ?? <ChevronUpDownIcon />}
    </ComboboxPrimitive.Trigger>
  );
});

const ComboboxPositioner = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Positioner>,
  ComponentProps<typeof ComboboxPrimitive.Positioner>
>(function ComboboxPositioner({ className, ...props }, ref) {
  return (
    <OverlayPortal>
      <ComboboxPrimitive.Positioner
        ref={ref}
        data-slot="combobox-positioner"
        className={clsx(styles.positioner, normalizeClassName(className))}
        {...props}
      />
    </OverlayPortal>
  );
});

const ComboboxContent = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Content>,
  ComponentProps<typeof ComboboxPrimitive.Content>
>(function ComboboxContent({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Content
      ref={ref}
      data-slot="combobox-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxEmpty = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Empty>,
  ComponentProps<typeof ComboboxPrimitive.Empty>
>(function ComboboxEmpty({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Empty
      ref={ref}
      data-slot="combobox-empty"
      className={clsx(styles.empty, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxList = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.List>,
  ComponentProps<typeof ComboboxPrimitive.List>
>(function ComboboxList({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.List
      ref={ref}
      data-slot="combobox-list"
      className={clsx(styles.list, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxItemGroup = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.ItemGroup>,
  ComponentProps<typeof ComboboxPrimitive.ItemGroup>
>(function ComboboxItemGroup({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.ItemGroup
      ref={ref}
      data-slot="combobox-item-group"
      className={clsx(styles.itemGroup, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxItemGroupLabel = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.ItemGroupLabel>,
  ComponentProps<typeof ComboboxPrimitive.ItemGroupLabel>
>(function ComboboxItemGroupLabel({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.ItemGroupLabel
      ref={ref}
      data-slot="combobox-item-group-label"
      className={clsx(styles.itemGroupLabel, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxItem = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.Item>,
  ComponentProps<typeof ComboboxPrimitive.Item>
>(function ComboboxItem({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.Item
      ref={ref}
      data-slot="combobox-item"
      className={clsx(styles.item, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxItemText = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.ItemText>,
  ComponentProps<typeof ComboboxPrimitive.ItemText>
>(function ComboboxItemText({ className, ...props }, ref) {
  return (
    <ComboboxPrimitive.ItemText
      ref={ref}
      data-slot="combobox-item-text"
      className={clsx(styles.itemText, normalizeClassName(className))}
      {...props}
    />
  );
});

const ComboboxItemIndicator = forwardRef<
  ComponentRef<typeof ComboboxPrimitive.ItemIndicator>,
  ComponentProps<typeof ComboboxPrimitive.ItemIndicator>
>(function ComboboxItemIndicator({ className, children, ...props }, ref) {
  return (
    <ComboboxPrimitive.ItemIndicator
      ref={ref}
      data-slot="combobox-item-indicator"
      className={clsx(styles.itemIndicator, normalizeClassName(className))}
      {...props}
    >
      {children ?? <CheckIcon />}
    </ComboboxPrimitive.ItemIndicator>
  );
});

type ComboboxOptionProps = Omit<
  ComponentProps<typeof ComboboxPrimitive.Item>,
  'asChild' | 'children'
> & {
  children: ReactNode;
  indicator?: ReactNode | false;
};

const ComboboxOption = forwardRef<ComponentRef<typeof ComboboxPrimitive.Item>, ComboboxOptionProps>(
  function ComboboxOption({ children, indicator, ...props }, ref) {
    return (
      <ComboboxItem ref={ref} {...props}>
        <ComboboxItemText>{children}</ComboboxItemText>
        {indicator !== false ? <ComboboxItemIndicator>{indicator}</ComboboxItemIndicator> : null}
      </ComboboxItem>
    );
  },
);

const Combobox = Object.assign(ComboboxRoot, {
  Root: ComboboxRoot,
  RootProvider: ComboboxRootProvider,
  Label: ComboboxLabel,
  Control: ComboboxControl,
  Input: ComboboxInput,
  ClearTrigger: ComboboxClearTrigger,
  Trigger: ComboboxTrigger,
  Positioner: ComboboxPositioner,
  Content: ComboboxContent,
  Empty: ComboboxEmpty,
  List: ComboboxList,
  ItemGroup: ComboboxItemGroup,
  ItemGroupLabel: ComboboxItemGroupLabel,
  Item: ComboboxItem,
  ItemText: ComboboxItemText,
  ItemIndicator: ComboboxItemIndicator,
  Option: ComboboxOption,
  Context: ComboboxPrimitive.Context,
});

export { Combobox, useCombobox, useComboboxContext };

@layer ui.components {
  @keyframes combobox-content-open {
    from {
      opacity: var(--combobox-content-closed-opacity, var(--popup-motion-starting-opacity, 0));
      translate: var(--popup-motion-starting-translate-x, 0)
        var(--popup-motion-starting-translate-y, 0);
      transform: scale(
        var(--combobox-content-closed-scale, var(--popup-motion-starting-scale, var(--scale-popup)))
      );
    }

    to {
      opacity: 1;
      translate: 0 0;
      transform: scale(1);
    }
  }

  @keyframes combobox-content-closed {
    from {
      opacity: 1;
      translate: 0 0;
      transform: scale(1);
    }

    to {
      opacity: var(--combobox-content-closed-opacity, var(--popup-motion-ending-opacity, 0));
      translate: var(--popup-motion-ending-translate-x, 0) var(--popup-motion-ending-translate-y, 0);
      transform: scale(
        var(--combobox-content-closed-scale, var(--popup-motion-ending-scale, var(--scale-popup)))
      );
    }
  }

  .root {
    box-sizing: border-box;
    display: flex;
    width: var(--combobox-width, 16rem);
    max-width: var(--combobox-max-width, 100%);
    min-width: 0;
    flex-direction: column;
    gap: var(--combobox-root-gap, 0.375rem);
    color: var(--combobox-color, var(--color-foreground));
  }

  .label {
    display: inline-flex;
    align-items: center;
    color: var(--combobox-label-color, var(--combobox-color, var(--color-foreground)));
    font-size: var(--combobox-label-font-size, var(--text-sm));
    font-weight: var(--combobox-label-font-weight, var(--weight-medium));
    line-height: var(--combobox-label-line-height, var(--line-height-text-sm));
    user-select: none;

    &[data-disabled] {
      opacity: var(--combobox-disabled-opacity, var(--opacity-disabled));
    }
  }

  .control {
    position: relative;
    display: flex;
    width: 100%;
    min-width: 0;
    align-items: center;
    border: var(--combobox-border-width, var(--border-width-sm)) solid
      var(--combobox-border-color, var(--color-border));
    border-radius: var(--combobox-radius, var(--radius-md));
    background-color: var(--combobox-bg, var(--color-background));
    color: var(--combobox-color, var(--color-foreground));
    outline: var(--combobox-focus-ring-width, var(--border-width-sm)) solid transparent;
    outline-offset: calc(var(--combobox-focus-ring-width, var(--border-width-sm)) * -1);
    transition:
      background-color var(--combobox-transition, var(--transition-default)),
      border-color var(--combobox-transition, var(--transition-default)),
      outline-color var(--combobox-transition, var(--transition-default));

    &[data-state='open'] {
      background-color: var(--combobox-bg-active, var(--color-muted));
      border-color: var(--combobox-focus-ring-color, var(--color-ring));
      outline-color: var(--combobox-focus-ring-color, var(--color-ring));
    }

    &[data-focus] {
      border-color: var(--combobox-focus-ring-color, var(--color-ring));
      outline-color: var(--combobox-focus-ring-color, var(--color-ring));
    }

    &[data-invalid] {
      border-color: var(--combobox-invalid-color, var(--color-destructive));
      outline-color: var(--combobox-invalid-color, var(--color-destructive));
    }

    &[data-disabled] {
      opacity: var(--combobox-disabled-opacity, var(--opacity-disabled));
    }

    &:not([data-disabled]) {
      @media (hover: hover) {
        &:hover:not(:has(.clearTrigger:hover)) {
          background-color: var(--combobox-bg-hover, var(--color-accent));
        }
      }
    }
  }

  .input {
    box-sizing: border-box;
    width: 100%;
    min-width: 0;
    height: var(--combobox-control-height, var(--size-lg));
    margin: 0;
    border: 0;
    border-radius: inherit;
    padding-inline: var(--combobox-input-padding-x-start, 0.875rem)
      var(--combobox-input-padding-x-end, 0.875rem);
    background: transparent;
    color: inherit;
    font: inherit;
    outline: 0;

    &::placeholder {
      color: var(--combobox-input-placeholder-color, var(--color-muted-foreground));
    }
  }

  .control:has(.trigger) .input {
    padding-inline-end: var(--combobox-input-padding-x-end-with-trigger, 2.75rem);
  }

  .control:has(.clearTrigger) .input {
    padding-inline-end: var(--combobox-input-padding-x-end-with-clear, 4.375rem);
  }

  .trigger,
  .clearTrigger {
    position: absolute;
    top: 50%;
    box-sizing: border-box;
    display: inline-flex;
    width: var(--combobox-action-size, 1.5rem);
    height: var(--combobox-action-size, 1.5rem);
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    margin: 0;
    border: 0;
    border-radius: var(--combobox-action-radius, var(--radius-sm));
    padding: 0;
    background: var(--combobox-action-bg, transparent);
    color: var(--combobox-icon-color, var(--color-muted-foreground));
    line-height: 0;
    transform: translateY(-50%);
    cursor: pointer;
    transition:
      background-color var(--combobox-transition, var(--transition-default)),
      color var(--combobox-transition, var(--transition-default)),
      opacity var(--combobox-transition, var(--transition-default));

    & > svg {
      display: block;
      width: var(--combobox-icon-size, 1rem);
      height: var(--combobox-icon-size, 1rem);
    }

    &:focus-visible {
      outline: var(--combobox-focus-ring-width, var(--border-width-sm)) solid
        var(--combobox-focus-ring-color, var(--color-ring));
      outline-offset: var(--combobox-focus-ring-offset, var(--border-width-sm));
    }

    &:not(:is([disabled], [data-disabled])) {
      @media (hover: hover) {
        &:hover {
          background-color: var(--combobox-action-bg-hover, var(--color-muted));
          color: var(--combobox-action-color-hover, var(--color-foreground));
        }
      }
    }

    &:is([disabled], [data-disabled]) {
      cursor: default;
    }
  }

  .trigger {
    right: var(--combobox-action-offset-right, 0.5rem);
  }

  .clearTrigger {
    right: calc(
      var(--combobox-action-offset-right, 0.5rem) + var(--combobox-action-size, 1.5rem) +
        var(--combobox-action-gap, 0.125rem)
    );
  }

  .positioner {
    z-index: var(--z-index);
    outline: 0;
  }

  .content {
    box-sizing: border-box;
    z-index: calc(var(--z-popup) + var(--layer-index, 0));
    display: flex;
    min-width: var(--reference-width);
    max-width: var(--available-width);
    max-height: min(var(--combobox-content-max-height, 24rem), var(--available-height));
    flex-direction: column;
    overflow: auto;
    border: var(--combobox-content-border-width, var(--border-width-sm)) solid
      var(--combobox-content-border-color, var(--color-border));
    border-radius: var(--combobox-radius, var(--radius-md));
    padding-block: var(--combobox-content-padding-y, var(--spacing-1));
    background-color: var(--combobox-content-bg, var(--color-popover));
    box-shadow: var(--combobox-content-shadow, var(--shadow-lg));
    color: var(--combobox-content-color, var(--color-popover-foreground));
    transform-origin: var(--transform-origin);
    outline: 0;
    overscroll-behavior: contain;
    scroll-padding-block: var(--combobox-content-padding-y, var(--spacing-1));

    &[data-state='open'] {
      animation: combobox-content-open
        var(
          --combobox-transition,
          var(--popup-motion-duration, var(--duration-normal))
            var(--popup-motion-easing, var(--ease-in-out))
        );
    }

    &[data-state='closed'] {
      animation: combobox-content-closed
        var(
          --combobox-transition,
          var(--popup-motion-duration, var(--duration-normal))
            var(--popup-motion-easing, var(--ease-in-out))
        );
    }
  }

  .list {
    display: flex;
    min-height: 0;
    flex-direction: column;
    overflow-y: auto;
    outline: 0;
    overscroll-behavior: contain;
    scroll-padding-block: var(--combobox-content-padding-y, var(--spacing-1));

    &[data-empty] {
      display: none;
    }
  }

  .empty {
    padding-block: var(--combobox-empty-padding-y, 0.75rem);
    padding-inline: var(--combobox-empty-padding-x, 1rem);
    color: var(--combobox-empty-color, var(--color-muted-foreground));
    font-size: var(--combobox-empty-font-size, var(--text-sm));
    line-height: var(--combobox-empty-line-height, var(--line-height-text-sm));
  }

  .itemGroup {
    display: flex;
    flex-direction: column;

    & + & {
      margin-top: var(--combobox-item-group-gap, var(--spacing-2));
    }
  }

  .itemGroupLabel {
    position: sticky;
    top: 0;
    z-index: 1;
    padding-block: var(--combobox-item-group-label-padding-y, 0.35rem);
    padding-inline: var(--combobox-item-group-label-padding-x, 0.625rem);
    background-color: var(--combobox-content-bg, var(--color-popover));
    color: var(--combobox-item-group-label-color, var(--color-muted-foreground));
    font-size: var(--combobox-item-group-label-font-size, var(--text-xs));
    font-weight: var(--combobox-item-group-label-font-weight, var(--weight-semibold));
    line-height: var(--combobox-item-group-label-line-height, var(--line-height-text-xs));
  }

  .item {
    box-sizing: border-box;
    position: relative;
    display: flex;
    width: calc(100% - var(--combobox-item-inset-x, var(--spacing-2)));
    min-height: var(--combobox-item-min-height, 2rem);
    align-items: center;
    justify-content: space-between;
    gap: var(--combobox-item-gap, var(--spacing-2));
    margin-inline: calc(var(--combobox-item-inset-x, var(--spacing-2)) / 2);
    border: var(--combobox-item-border-width, 0) solid
      var(--combobox-item-border-color, transparent);
    border-radius: var(--combobox-item-radius, var(--radius-sm));
    padding-block: var(--combobox-item-padding-y, var(--spacing-2));
    padding-inline: var(--combobox-item-padding-x, 0.625rem);
    background-color: var(--combobox-item-bg, transparent);
    color: var(--combobox-item-color, var(--combobox-content-color, var(--color-foreground)));
    font: inherit;
    font-size: var(--combobox-item-font-size, var(--text-sm));
    line-height: var(--combobox-item-line-height, var(--line-height-text-sm));
    outline: 0;
    cursor: default;
    user-select: none;

    &[data-highlighted] {
      background-color: var(--combobox-highlight-bg, var(--color-accent));
      color: var(--combobox-highlight-color, var(--color-accent-foreground));
    }

    &[data-state='checked'] {
      color: var(
        --combobox-item-checked-color,
        var(--combobox-item-color, var(--color-foreground))
      );
    }

    &[data-disabled] {
      color: var(--combobox-item-disabled-color, var(--color-muted-foreground));
      opacity: var(--combobox-disabled-opacity, var(--opacity-disabled));
      pointer-events: none;
    }
  }

  .itemText {
    min-width: 0;
    flex: 1;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .itemIndicator {
    display: inline-flex;
    width: var(--combobox-item-indicator-size, 0.75rem);
    height: var(--combobox-item-indicator-size, 0.75rem);
    flex-shrink: 0;
    align-items: center;
    justify-content: center;

    & > svg {
      width: 100%;
      height: 100%;
    }
  }
}
